"use strict";(globalThis.webpackChunkdocusaurus_temp=globalThis.webpackChunkdocusaurus_temp||[]).push([[9024],{6273(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>d,frontMatter:()=>o,metadata:()=>i,toc:()=>h});var i=n(4163),a=n(4848),s=n(8453);const o={title:"Twenty Years of Agile, One Year of AI \u2014 Here's What Survived",date:new Date("2026-03-09T00:00:00.000Z"),authors:["austin"],tags:["ai","cloud-computing","leadership","career-development"],description:"Twenty years of Agile have shaped how I think about software. Here's why I believe Agile principles aren't just still relevant in the AI coding era \u2014 they're more important than ever."},r=void 0,l={authorsImageUrls:[void 0]},h=[{value:"The New Design Principles for AI Coding",id:"the-new-design-principles-for-ai-coding",level:2},{value:"My Own Reaction to &quot;File as Truth&quot;",id:"my-own-reaction-to-file-as-truth",level:2},{value:"Agile Principles, Mapped to AI Coding",id:"agile-principles-mapped-to-ai-coding",level:2},{value:"Test-Driven Development: The Closing Loop",id:"test-driven-development-the-closing-loop",level:3},{value:"Small Iterations, Frequent Delivery",id:"small-iterations-frequent-delivery",level:3},{value:"Pair Programming and Individual Interaction",id:"pair-programming-and-individual-interaction",level:3},{value:"Refactoring: More Courage, Not Less",id:"refactoring-more-courage-not-less",level:3},{value:"Working Software as the Measure of Progress",id:"working-software-as-the-measure-of-progress",level:3},{value:"Retrospection and Embracing Change",id:"retrospection-and-embracing-change",level:3},{value:"The Bigger Picture",id:"the-bigger-picture",level:2}];function c(e){const t={code:"code",em:"em",h2:"h2",h3:"h3",li:"li",ol:"ol",p:"p",strong:"strong",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.p,{children:"I grew up as a developer reading Martin Fowler and Kent Beck. The Agile Manifesto, the refactoring patterns, test-driven development \u2014 these weren't just methodologies I was handed. They were the lens through which I learned to think about software quality, team dynamics, and sustainable delivery."}),"\n",(0,a.jsxs)(t.p,{children:["Now I'm spending significant time with AI coding tools \u2014 Vibe Coding, Claude Code, spec-driven workflows \u2014 and a question keeps surfacing: ",(0,a.jsx)(t.em,{children:"do these principles still apply?"})]}),"\n",(0,a.jsx)(t.p,{children:"My answer, after a hands-on 50K-line project experiment, is yes. Not only do they apply \u2014 several of them become load-bearing pillars in an AI-augmented workflow."}),"\n",(0,a.jsx)(t.h2,{id:"the-new-design-principles-for-ai-coding",children:"The New Design Principles for AI Coding"}),"\n",(0,a.jsx)(t.p,{children:"A friend of mine did a deep, systematic study of AI coding tools and frameworks. He synthesized seven core principles for what he calls \"AI Native\" development \u2014 essentially Software 3.0. They're worth understanding before discussing Agile, because they frame the new context we're working in:"}),"\n",(0,a.jsxs)(t.ol,{children:["\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"File as Truth"})," \u2014 Store AI memory, config, and state in human-readable local files. The file system is the universal interface between humans and AI."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Explicit State"})," \u2014 AI must continuously record what it's doing, where it is, and what problems it's encountered. The \"three-file pattern\": ",(0,a.jsx)(t.code,{children:"plan.md"}),", ",(0,a.jsx)(t.code,{children:"status.md"}),", ",(0,a.jsx)(t.code,{children:"log.md"}),"."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Plan Before Execute"})," \u2014 Separate design authority from execution authority. AI generates a plan, humans approve it, then AI builds."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Validation as Closed Loop"})," \u2014 Don't trust AI's self-assessment. Build deterministic, test-based auto-correction loops. Red/green TDD is the mechanism."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Tiered Memory"})," \u2014 Structure AI memory across volatile context (RAM), session logs, and persistent disk files. Actively manage what gets compressed or forgotten."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Skill as Asset"})," \u2014 Encapsulate AI capabilities as modular, reusable skills. AI learns to expand its own toolbox."]}),"\n",(0,a.jsxs)(t.li,{children:[(0,a.jsx)(t.strong,{children:"Context as Budget"})," \u2014 Tokens are expensive and scarce. Load tools on demand, prune redundant output, cache prompts."]}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"These are well-constructed. But reading through them, something struck me: most of these aren't new ideas dressed in AI clothes. They're old ideas that become newly critical at AI scale."}),"\n",(0,a.jsx)(t.h2,{id:"my-own-reaction-to-file-as-truth",children:'My Own Reaction to "File as Truth"'}),"\n",(0,a.jsxs)(t.p,{children:['The principle that made me think the hardest was "File as Truth." In traditional Agile, we said ',(0,a.jsx)(t.strong,{children:"code is truth"})," \u2014 the code is the unambiguous, definitive representation of what the system actually does. Documentation lies. Requirements drift. But the code runs."]}),"\n",(0,a.jsx)(t.p,{children:"AI-native thinking flips this: keep the truth in files (specs, architecture docs, structured state), and let AI generate the implementation."}),"\n",(0,a.jsx)(t.p,{children:"I see the appeal. Without anchoring AI to structured context, it will hallucinate, drift, and invent. Having a canonical document that survives across sessions \u2014 that the AI reads before acting \u2014 is clearly better than relying on prompt memory alone."}),"\n",(0,a.jsxs)(t.p,{children:["But I'm not fully convinced of the flip. ",(0,a.jsx)(t.strong,{children:"The implementation gap is real."})," A natural-language document is inherently ambiguous; the same spec can produce very different code depending on how the AI interprets it. The more latitude you give AI on implementation, the more you need to verify the result is actually what you intended."]}),"\n",(0,a.jsx)(t.p,{children:'The answer, I think, isn\'t to choose between "code is truth" and "file is truth." It\'s to recognize that both co-exist and must stay in sync. The file defines intent; the code is the executable artifact; the tests verify they match. The problem is that AI can generate documents as easily as code, so without discipline, you end up maintaining two rapidly-diverging sources of truth with no reliable bridge.'}),"\n",(0,a.jsx)(t.p,{children:"This is where Agile principles come back in with force."}),"\n",(0,a.jsx)(t.h2,{id:"agile-principles-mapped-to-ai-coding",children:"Agile Principles, Mapped to AI Coding"}),"\n",(0,a.jsx)(t.p,{children:"The Agile Manifesto has four values and twelve principles. I won't enumerate all of them \u2014 but here are the ones that resonate most directly with AI-augmented development, and what I've observed about how each one applies."}),"\n",(0,a.jsx)(t.h3,{id:"test-driven-development-the-closing-loop",children:"Test-Driven Development: The Closing Loop"}),"\n",(0,a.jsx)(t.p,{children:'TDD was always my favorite practice. Write the failing test first, then write the code to make it pass. It forces you to define success before you start building, and it creates an automated verification mechanism that doesn\'t require you to remember what "done" looks like.'}),"\n",(0,a.jsxs)(t.p,{children:["In AI coding, TDD becomes something more important: ",(0,a.jsx)(t.strong,{children:"it's how you close the loop."})]}),"\n",(0,a.jsx)(t.p,{children:'AI is creative but non-deterministic. Left to its own judgment, it will implement something that plausibly looks correct. With a failing test, it has an unambiguous target. More importantly, it can run the test itself, observe the failure, and self-correct without human intervention. This is what "Validation as Closed Loop" actually means in practice. The principle is elegant; TDD is the mechanism.'}),"\n",(0,a.jsx)(t.p,{children:'Without tests, you\'re reviewing AI-generated code by reading it \u2014 a slow, error-prone process that doesn\'t scale. With tests, you shift from "is this code right?" to "does this code pass?" That\'s a much more tractable question.'}),"\n",(0,a.jsx)(t.h3,{id:"small-iterations-frequent-delivery",children:"Small Iterations, Frequent Delivery"}),"\n",(0,a.jsxs)(t.p,{children:["This principle gets stronger in the AI era, but the ",(0,a.jsx)(t.em,{children:"unit of iteration"})," changes."]}),"\n",(0,a.jsx)(t.p,{children:"In traditional Agile, a sprint might be two weeks. In AI-augmented development, meaningful feedback loops operate at the granularity of minutes. A useful heuristic I've encountered: if a task takes more than five minutes to complete, it should probably be broken into smaller tasks."}),"\n",(0,a.jsx)(t.p,{children:"The reasoning is that AI context windows are finite. Long sessions accumulate drift \u2014 the AI gradually loses track of earlier constraints, architectural decisions, and your stated preferences. Shorter tasks that complete and close maintain higher coherence. You also get faster human review cycles, which is where the real quality control happens."}),"\n",(0,a.jsx)(t.p,{children:"The tricky part is calibrating granularity. Tasks that are too small generate too much overhead \u2014 constant context-loading and handoffs. Tasks that are too large drift. Finding the right unit of work is genuinely hard, and I think it's going to become one of the core skills of experienced AI developers."}),"\n",(0,a.jsx)(t.h3,{id:"pair-programming-and-individual-interaction",children:"Pair Programming and Individual Interaction"}),"\n",(0,a.jsx)(t.p,{children:"This is the Agile principle I find most personally relevant, and the one I feel most tension around."}),"\n",(0,a.jsx)(t.p,{children:"Pair programming at its best is a continuous conversation \u2014 two minds colliding on the same problem, catching each other's mistakes, sharing knowledge, and building something better together than either could alone. The value isn't just the code produced; it's the thinking process."}),"\n",(0,a.jsx)(t.p,{children:"With AI, there's a version of this that feels authentic: I give a rough requirement, the AI designs an approach, breaks it into tasks, builds a prototype, I use it and give feedback, we iterate. This works remarkably well for UI refinement, performance tuning, and cases where I don't fully understand what I want until I see something tangible."}),"\n",(0,a.jsx)(t.p,{children:"But there's a failure mode I've noticed. Heavily structured frameworks \u2014 things like SpecKit or detailed plan-first workflows \u2014 can over-formalize the interaction. You end up managing documents and approvals more than you're actually collaborating. The \"pair\" feeling disappears."}),"\n",(0,a.jsx)(t.p,{children:"My current view: stay in the conversation longer than the frameworks suggest. Resist the urge to hand off too early. The value of pair programming with AI isn't just speed \u2014 it's the back-and-forth that surfaces what you actually want to build."}),"\n",(0,a.jsx)(t.h3,{id:"refactoring-more-courage-not-less",children:"Refactoring: More Courage, Not Less"}),"\n",(0,a.jsx)(t.p,{children:"Refactoring has always been about managing the accumulation of complexity. Small design improvements, continuously applied, prevent the architecture from calcifying into something unmaintainable."}),"\n",(0,a.jsxs)(t.p,{children:["The interesting thing about AI and refactoring is that AI gives you ",(0,a.jsx)(t.em,{children:"more courage"})," to refactor, not less."]}),"\n",(0,a.jsx)(t.p,{children:"In traditional development, refactoring required careful attention to not break existing behavior. IDE tools helped \u2014 but they were limited to mechanical transformations like renaming and extraction. Anything structural required deep understanding of the codebase."}),"\n",(0,a.jsx)(t.p,{children:"With AI, you can describe a structural change at a higher level of abstraction and have it applied across a large codebase with much lower risk of human error. The AI understands context in ways that text-replacement tools do not. This lowers the cost of refactoring, which means you can do it more frequently, which means the codebase stays in better shape."}),"\n",(0,a.jsxs)(t.p,{children:["The risk, though, is the opposite failure mode: ",(0,a.jsx)(t.em,{children:"not"})," refactoring. If you're solely focused on delivering feature after feature with AI, you can accumulate complexity faster than ever. Ten features in ten sessions, without a refactoring pass between them, and you may end up with code that no human can review \u2014 and eventually, that even AI can't reason about coherently."]}),"\n",(0,a.jsx)(t.h3,{id:"working-software-as-the-measure-of-progress",children:"Working Software as the Measure of Progress"}),"\n",(0,a.jsx)(t.p,{children:"Agile is explicit: working software, not documentation, is the primary measure of progress. This puts it in direct tension with AI-native thinking's emphasis on files and documentation as truth."}),"\n",(0,a.jsx)(t.p,{children:"I don't think the tension is unresolvable, but it does require active management. The danger in AI development is documentation inflation. AI can generate documentation easily and enthusiastically. If you're not careful, you end up with a sprawling set of spec files, plan files, and status files that nobody is maintaining \u2014 least of all the AI, which has long since moved on to other sessions."}),"\n",(0,a.jsxs)(t.p,{children:["The discipline I've settled on: documentation should be ",(0,a.jsx)(t.strong,{children:"minimal, structural, and kept in sync by automated means where possible."})," A CLAUDE.md that captures architecture decisions and conventions. Tests that document behavior. As little else as possible. The more documentation you have, the more surface area there is for inconsistency."]}),"\n",(0,a.jsx)(t.p,{children:"Working software remains the truth. The rest is scaffolding."}),"\n",(0,a.jsx)(t.h3,{id:"retrospection-and-embracing-change",children:"Retrospection and Embracing Change"}),"\n",(0,a.jsx)(t.p,{children:"The last two principles are deeply linked. Agile retrospectives are about systematically capturing what you've learned so that future iterations improve. Embracing change means treating new requirements as a natural part of the process rather than a disruption."}),"\n",(0,a.jsx)(t.p,{children:'In AI tooling, the equivalents are emerging. Tools like SpecKit and OpenSpec have a concept of "achieved" \u2014 lessons learned from completed work that get folded back into your project\'s guiding principles (CLAUDE.md or similar). This is retrospection, formalized.'}),"\n",(0,a.jsx)(t.p,{children:"Mechanisms like Ralphloop \u2014 which allow an AI to iterate on its own approach autonomously \u2014 are a form of embracing change, though they require careful oversight to avoid runaway scope drift."}),"\n",(0,a.jsx)(t.p,{children:"The underlying idea holds: learning should compound across iterations. Whether that learning lives in a retrospective document, an updated CLAUDE.md, or a refined test suite, the principle is the same. Don't repeat the same mistakes."}),"\n",(0,a.jsx)(t.h2,{id:"the-bigger-picture",children:"The Bigger Picture"}),"\n",(0,a.jsx)(t.p,{children:"There's a pattern across all of these: Agile principles were designed to manage complexity and uncertainty in human-scale software development. AI doesn't eliminate complexity and uncertainty \u2014 in some ways, it amplifies them. The speed of generation goes up; the need for coherent architecture and verified correctness goes up equally."}),"\n",(0,a.jsxs)(t.p,{children:["A friend who researches AI coding described the ideal as: ",(0,a.jsx)(t.strong,{children:'"File provides memory, you provide discipline."'})," I think that's right. The file doesn't discipline itself. The tests don't write themselves. The refactoring doesn't happen automatically."]}),"\n",(0,a.jsxs)(t.p,{children:["What AI does is lower the cost of execution so dramatically that the bottleneck shifts. The bottleneck used to be writing the code. Now it's ",(0,a.jsx)(t.em,{children:"knowing what to build and verifying that what was built is correct"}),". Those are judgment problems. They're exactly what Agile was designed to develop in engineers."]}),"\n",(0,a.jsx)(t.p,{children:"I spent twenty years learning these principles from books and practice. I'm glad I did. They don't just survive the AI transition \u2014 they've become more essential."}),"\n",(0,a.jsx)(t.p,{children:"The engineers who will thrive in this environment aren't the ones who generate the most code. They're the ones who know how to close loops, calibrate iteration size, stay in the conversation, refactor at the right moments, and keep working software at the center."}),"\n",(0,a.jsx)(t.p,{children:"That sounds a lot like Agile to me."})]})}function d(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},8453(e,t,n){n.d(t,{R:()=>o,x:()=>r});var i=n(6540);const a={},s=i.createContext(a);function o(e){const t=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),i.createElement(s.Provider,{value:t},e.children)}},4163(e){e.exports=JSON.parse('{"permalink":"/blogs/blog/2026/03/09/agile-development-in-ai-coding","source":"@site/blog/2026-03-09-agile-development-in-ai-coding.md","title":"Twenty Years of Agile, One Year of AI \u2014 Here\'s What Survived","description":"Twenty years of Agile have shaped how I think about software. Here\'s why I believe Agile principles aren\'t just still relevant in the AI coding era \u2014 they\'re more important than ever.","date":"2026-03-09T00:00:00.000Z","tags":[{"inline":true,"label":"ai","permalink":"/blogs/blog/tags/ai"},{"inline":true,"label":"cloud-computing","permalink":"/blogs/blog/tags/cloud-computing"},{"inline":true,"label":"leadership","permalink":"/blogs/blog/tags/leadership"},{"inline":true,"label":"career-development","permalink":"/blogs/blog/tags/career-development"}],"readingTime":9.45,"hasTruncateMarker":true,"authors":[{"name":"Austin Xu","title":"Cloud Platform Engineering Leader @ eBay","url":"https://github.com/austinxyz","email":"austin.xyz@gmail.com","socials":{"linkedin":"https://www.linkedin.com/in/austin-yanzhao-xu-6301ab6","github":"https://github.com/austinxyz"},"imageURL":"https://github.com/austinxyz.png","key":"austin","page":null}],"frontMatter":{"title":"Twenty Years of Agile, One Year of AI \u2014 Here\'s What Survived","date":"2026-03-09T00:00:00.000Z","authors":["austin"],"tags":["ai","cloud-computing","leadership","career-development"],"description":"Twenty years of Agile have shaped how I think about software. Here\'s why I believe Agile principles aren\'t just still relevant in the AI coding era \u2014 they\'re more important than ever."},"unlisted":false,"prevItem":{"title":"How Ops Engineers Can Stay Relevant in the Age of AI: Becoming a Platform Engineer","permalink":"/blogs/blog/2026/03/16/platform-engineer-vs-ops-engineer"},"nextItem":{"title":"[7/6] Claude Code: From Vibe Coding to Spec-Driven Development","permalink":"/blogs/blog/2026/03/06/claude-code-spec-driven-development"}}')}}]);